INSERT INTO public.properties (webflow_id, slug, name, pin_code, price, price_per_sqft, bedrooms, bathrooms, built_year, area_sqft, parking_description, monthly_hoa_fee, description_html, neighborhood_html, amenities_html, features_html, pricing_tax_history, main_image, images, floor_plans, video, map_image, map_link, next_open_house_at, next_open_house_timing, neighborhood_id, property_type_id, architecture_style_id, status_id) VALUES
('69a99a9a134871caed1ded6c','1694-clay-drive','1694 Clay Drive','94024',5250000,NULL,5,3,1968,2569,'4',NULL,'<p>Discover the magic of 1694 Clay Drive, a stunning 5-bedroom, 3-bathroom Eichler masterpiece in coveted Los Altos. Spanning 2,569 sq ft on a 10,000 sq ft lot, this single-level home built in 1968 was fully renovated in 2015-2016, blending mid-century charm with modern luxury. Step through the vibrant orange door into a light-filled sanctuary where sunlight streams through skylights and dual-pane windows, illuminating the open layout. The gourmet kitchen boasts Italian marble counters, custom cabinetry, pro appliances (Sub-Zero, Thermador), and a built-in pantry—perfect for morning rituals in the sun. The atrium courtyard invites serene moments, with hummingbirds and gentle breezes enhancing the paradise feel. Unwind in the primary suite with spa-like bath, or enjoy the radiant floor heating throughout. Outside, a private pool with new gas heater (2020), solar cover, and lush landscaping (redone 1.5-2.5 years ago) offers endless family fun. Recent updates include custom California Closets, Hunter Douglas blackout blinds, Nest smart home tech (thermostat, cameras, smoke detectors), Rachio irrigation, new hot water heater (2023), dishwasher, ventless dryer, exterior paint, and professional alarm system.Cherish memories in rooms echoing with laughter, board games, and milestones. Award-winning schools (Montclaire Elem, Cupertino Middle, Homestead High) and proximity to parks, trails, tech hubs (Google, Apple), and amenities make this more than a home—it''s a legacy.</p>',NULL,NULL,NULL,NULL,'{"fileId": "69a99697fb4d4a120c2ccdb7", "url": "https://cdn.prod.website-files.com/65a1ca4354f63bd7376b503e/69a99697fb4d4a120c2ccdb7_1694%20Clay%20Dr-Twilight-3.jpg", "alt": null}'::jsonb,'[{"fileId": "69a99697fb4d4a120c2ccdb7", "url": "https://cdn.prod.website-files.com/65a1ca4354f63bd7376b503e/69a99697fb4d4a120c2ccdb7_1694%20Clay%20Dr-Twilight-3.jpg", "alt": null}]'::jsonb,'[{"fileId": "69a99a888e38399531dd0e42", "url": "https://cdn.prod.website-files.com/65a1ca4354f63bd7376b503e/69a99a888e38399531dd0e42_Eichler.png", "alt": null}]'::jsonb,'{"url": "https://youtu.be/oqmV7nMb5PM", "title": "Just Listed | 1694 Clay Drive, Los Altos", "thumbnail_url": "https://i.ytimg.com/vi/oqmV7nMb5PM/hqdefault.jpg"}'::jsonb,NULL,NULL,NULL,NULL,(SELECT id FROM public.neighborhoods WHERE webflow_id = '69a995dc2c643929c034b54d'),(SELECT id FROM public.property_types WHERE webflow_id = '65a1ca4354f63bd7376b505b'),NULL,(SELECT id FROM public.statuses WHERE webflow_id = '65a1cc6ef23e0308ab933b77')),
